section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/competitive-intelligence-methods.json",
  "title": "Competitive Intelligence Methods",
  "type": "object",
  "required": [
    "artefact_id",
    "signal_needed",
    "methods_selected",
    "methods_rejected",
    "collection_plan",
    "false_signal_guards",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "signal_needed": {
      "type": "string",
      "description": "pricing|roadmap|hires|funding|churn|positioning",
      "minLength": 1
    },
    "methods_selected": {
      "type": "array",
      "description": "\u22651 method ids from the catalogue",
      "minItems": 1
    },
    "methods_rejected": {
      "type": "array",
      "description": "{method, reason}",
      "minItems": 1
    },
    "collection_plan": {
      "type": "object",
      "description": "cadence, owner, storage path"
    },
    "false_signal_guards": {
      "type": "array",
      "description": "guard rules per chosen method",
      "minItems": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
  "artefact_id": "competitive-intelligence-methods-2026-05-23",
  "signal_needed": "draft",
  "methods_selected": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "methods_rejected": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "collection_plan": {
    "key": "value"
  },
  "false_signal_guards": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "evidence": [
    {
      "source": "https://example.com/transcript/1",
      "citation": "verbatim user quote"
    }
  ]
}
